  }
  const pkgDir = meta.path;
  if (pkgDir) {
    const candidates = ['NOTICE', 'NOTICE.txt', 'NOTICE.md', 'Notice', 'notice', 'notice.txt'];
    for (const f of candidates) {
      try {
        const noticeCaminho = path.join(pkgDir, f);
        const stat = await fs.stat(noticeCaminho).catch(() => null);
        if (stat && stat.isFile()) {
          const ncontent = nl(await fs.readFile(noticeCaminho, 'utf-8')).trim();
          if (ncontent) {
            lines.push('');
            lines.push('--- Início do NOTICE ---');
            lines.push(ncontent);
            lines.push('--- Fim do NOTICE ---');
          }
          break;
        }
      } catch {}
    }
  }
  lines.push('');
  return lines.join('\n');
}
export async function generateNotices({
  root = process.cwd(),
  ptBr = false,
  output
}: GenerateNoticesOptions = {}): Promise<{
  output: string;
  packages: number;
}> {
  const pkg = JSON.parse(await fs.readFile(path.join(root, 'package.json'), 'utf-8'));
  const projectNome = `${pkg.name}@${pkg.version}`;
  const projectLicenca = pkg.license || 'UNSPECIFIED';
  let results: Record<string, RenderPackageMeta> | null = null;
  const cacheCaminho = path.join(root, '.prometheus', 'licenses.json');
  try {
    const buf = await fs.readFile(cacheCaminho, 'utf-8');
    results = JSON.parse(buf);
  } catch {}
  if (!results) {
    try {
      const {
        createRequire
      } = await import('node:module');
      const require = createRequire(import.meta.url);
      const licenseChecker = require('license-checker-rseidelsohn');
      results = await new Promise<Record<string, RenderPackageMeta>>((resolve, reject) => {
        licenseChecker.init({
          start: root,
          production: true,
          direct: false,
          relativeLicensePath: true,
          json: true
        }, (err: Error | null, json: Record<string, RenderPackageMeta>) => {
          if (err) reject(err);else resolve(json);
        });
      });
    } catch {

      // ignore
    }}
  if (!results) {
    try {
      const {
        stdout
      } = await execFile('npx', ['--yes', 'license-checker-rseidelsohn', '--production', '--json'], {
        maxBuffer: 10 * 1024 * 1024
      });
      results = JSON.parse(stdout);
    } catch {
      try {
        const cmd = 'npx --yes license-checker-rseidelsohn --production --json';
        const {
          stdout
        } = await exec(cmd, {
          maxBuffer: 10 * 1024 * 1024
        });
        results = JSON.parse(stdout);
      } catch {
        throw new Error('Failed to obtain license information via cache, API or npx');
      }
    }
  }
  try {
    const dir = path.join(root, '.prometheus');
    await fs.mkdir(dir, {
      recursive: true
    });
    await fs.writeFile(path.join(dir, 'licenses.json'), JSON.stringify(results, null, 2), 'utf-8');
  } catch {}
  const entries = Object.entries(results || {}).filter(([id]) => !id.startsWith(`${pkg.name}@`)).sort((a, b) => a[0].localeCompare(b[0]));
  const parts = [header({
    projectNome,
    license: projectLicenca,
    ptBr
  })];
  for (const [id, meta] of entries) {
    parts.push(await renderPackageBlock(id, meta));
  }
  const finalTxt = parts.join('\n');
  const out = output ? path.resolve(root, output) : path.join(root, ptBr ? 'AVISOS-DE-TERCEIROS.pt-BR.txt' : 'THIRD-PARTY-NOTICES.txt');
  await fs.writeFile(out, finalTxt, 'utf-8');
  return {
    output: out,
    packages: entries.length
  };
}

