const { log, MENSAGENS_RELATORIOS_ANALISE, RelatorioAsyncPatternsMensagens } = getMessages();

/**
 * Categoriza arquivo baseado no path
 */
function categorizarArquivo(relPath: string): AsyncCategoria {
  if (relPath.includes('cli/')) return 'cli';
  if (relPath.includes('analistas/')) return 'analistas';
  if (relPath.includes('core/') || relPath.includes('nucleo/')) return 'core';
  if (relPath.includes('guardian/')) return 'guardian';
  if (relPath.includes('auto/') || relPath.includes('zeladores/')) return 'auto';
  return 'outros';
}

/**
 * Extrai total de promises de uma mensagem
 */
function extrairTotalPromises(mensagem: string): number {
  const match = mensagem.match(/\((\d+) mais\)/);
  if (match) {
    return parseInt(match[1], 10) + 1;
  }
  return 1;
}

/**
 * Agrupa ocorrências por arquivo
 */
function agruparPorArquivo(ocorrencias: Ocorrencia[]): Map<string, AsyncIssuesArquivo> {
  const porArquivo = new Map<string, AsyncIssuesArquivo>();
  for (const issue of ocorrencias) {
    const arquivo = issue.relPath;
    if (!porArquivo.has(arquivo)) {
      porArquivo.set(arquivo, {
        ocorrencias: [],
        nivel: (issue.nivel || 'info') as 'erro' | 'aviso' | 'info',
        total: 0
      });
    }
    const info = porArquivo.get(arquivo);
    if (!info) continue;
    info.ocorrencias.push({
      linha: issue.linha,
      mensagem: issue.mensagem,
      nivel: (issue.nivel || 'info') as 'erro' | 'aviso' | 'info'
    });
    info.total += extrairTotalPromises(issue.mensagem);
  }
  return porArquivo;
}

/**
 * Analisa padrões async/await de um relatório
 */
export async function analisarAsyncPatterns(ocorrencias: Ocorrencia[], options: AsyncAnalysisOptions = {}): Promise<AsyncAnalysisReport> {
  const topN = options.topN || 20;

  // Filtrar apenas unhandled-async
  const asyncIssues = ocorrencias.filter(o => o.mensagem && o.mensagem.includes('unhandled-async'));
  log.info(MENSAGENS_RELATORIOS_ANALISE.asyncPatterns.titulo);
  log.info(RelatorioAsyncPatternsMensagens.totalOcorrencias.replace('{total}', String(asyncIssues.length)));

  // Agrupar por arquivo
  const porArquivo = agruparPorArquivo(asyncIssues);

  // Ordenar por total (decrescente)
  const arquivosOrdenados = Array.from(porArquivo.entries()).map(([arquivo, info]): AsyncArquivoRanqueado => ({
    arquivo,
    total: info.total,
    nivel: (info.nivel || 'info') as 'erro' | 'aviso' | 'info'
  })).sort((a, b) => b.total - a.total);

  // Top arquivos
  log.info(RelatorioAsyncPatternsMensagens.topArquivos.replace('{total}', String(Math.min(topN, arquivosOrdenados.length))));
  for (let i = 0; i < Math.min(topN, arquivosOrdenados.length); i++) {
    const {
      arquivo,
      total,
      nivel
    } = arquivosOrdenados[i];
    const nivelIcon = nivel === 'erro' ? '' : nivel === 'aviso' ? '' : 'ℹ';
    log.info(`${i + 1}. ${nivelIcon} ${arquivo}`);
    log.info(RelatorioAsyncPatternsMensagens.promiseSemTratamento.replace('{total}', String(total)));
    log.info(RelatorioAsyncPatternsMensagens.prioridade.replace('{nivel}', nivel.toUpperCase()));
  }

  // Estatísticas por categoria
  const categorias: Record<AsyncCategoria, AsyncCategoriaStats> = {
    cli: {
      totalArquivos: 0,
      totalPromises: 0
    },
    analistas: {
      totalArquivos: 0,
      totalPromises: 0
    },
    core: {
      totalArquivos: 0,
      totalPromises: 0
    },
    guardian: {
      totalArquivos: 0,
      totalPromises: 0
    },
    auto: {
      totalArquivos: 0,
      totalPromises: 0
    },
    outros: {
      totalArquivos: 0,
      totalPromises: 0
    }
  };
  for (const {
    arquivo,
    total
  } of arquivosOrdenados) {
    const categoria = categorizarArquivo(arquivo);
    categorias[categoria].totalArquivos++;
    categorias[categoria].totalPromises += total;
  }
  log.info(RelatorioAsyncPatternsMensagens.distribuicaoCategoria);
  for (const [cat, stats] of Object.entries(categorias)) {
    if (stats.totalArquivos > 0) {
      log.info(RelatorioAsyncPatternsMensagens.categoriaStats.replace('{categoria}', cat.toUpperCase()).replace('{arquivos}', String(stats.totalArquivos)).replace('{promises}', String(stats.totalPromises)));
    }
  }

  // Recomendações
  if (options.includeRecomendacoes !== false) {
    const criticos = arquivosOrdenados.filter(a => a.nivel === 'erro');
    const altos = arquivosOrdenados.filter(a => a.nivel === 'aviso');
    log.info(MENSAGENS_RELATORIOS_ANALISE.asyncPatterns.recomendacoes);
    if (criticos.length > 0) {
      log.info(MENSAGENS_RELATORIOS_ANALISE.asyncPatterns.critico);
      for (const {
        arquivo
      } of criticos.slice(0, 5)) {
        log.info(`   - ${arquivo}`);
      }
    }
    if (altos.length > 0) {
      log.info(MENSAGENS_RELATORIOS_ANALISE.asyncPatterns.alto);
      for (const {
        arquivo
      } of altos.slice(0, 10)) {
        log.info(`   - ${arquivo}`);
      }
    }
    log.info(RelatorioAsyncPatternsMensagens.proximosPassos);
    log.info(RelatorioAsyncPatternsMensagens.passo1);
    log.info(RelatorioAsyncPatternsMensagens.passo2);
    log.info(RelatorioAsyncPatternsMensagens.passo3);
    log.info(RelatorioAsyncPatternsMensagens.passo4);
  }

  // Montar relatório
  const report: AsyncAnalysisReport = {
    timestamp: new Date().toISOString(),
    totalIssues: asyncIssues.length,
    totalFiles: porArquivo.size,
    topArquivos: arquivosOrdenados.slice(0, topN),
    categorias
  };
  if (options.includeRecomendacoes !== false) {
    const criticos = arquivosOrdenados.filter(a => a.nivel === 'erro');
    const altos = arquivosOrdenados.filter(a => a.nivel === 'aviso');
    report.recomendacoes = {
      criticos: criticos.slice(0, 5).map(a => a.arquivo),
      altos: altos.slice(0, 10).map(a => a.arquivo),
      proximosPassos: [
        RelatorioAsyncPatternsMensagens.passo1.replace('. ', ''),
        RelatorioAsyncPatternsMensagens.passo2.replace('. ', ''),
        RelatorioAsyncPatternsMensagens.passo3.replace('. ', ''),
        RelatorioAsyncPatternsMensagens.passo4.replace('. ', ''),
      ]
    };
  }
  return report;
}

/**
 * Salva relatório de análise async
 */
export async function salvarRelatorioAsync(report: AsyncAnalysisReport, outputCaminho: string): Promise<void> {
  await salvarEstado(outputCaminho, report);
  log.sucesso(MENSAGENS_RELATORIOS_ANALISE.asyncPatterns.salvo(outputCaminho));
}

/**
 * Executa análise completa e salva relatório
 */
export async function executarAnaliseAsync(ocorrencias: Ocorrencia[], baseDir: string, options: AsyncAnalysisOptions = {}): Promise<void> {
  const report = await analisarAsyncPatterns(ocorrencias, options);
  const reportCaminho = path.join(baseDir, 'reports', 'async-analysis-report.json');
  await salvarRelatorioAsync(report, reportCaminho);
}

// SPDX-License-Identifier: MIT
import { getMessages } from '@core/messages';
import type { ConselhoContextoPrometheus } from '@prometheus';

const { logConselheiro } = getMessages();

// Re-exporta para compatibilidade com nome original
export type ConselhoContexto = ConselhoContextoPrometheus;

export function emitirConselhoPrometheus(
  estresse: ConselhoContextoPrometheus,
): void {
  const {
    hora = new Date().getHours(),
    arquivosParaCorrigir = 0,
    arquivosParaPodar = 0,
  } = estresse;

  const madrugada = hora >= 23 || hora < 4;
  const muitosArquivos = arquivosParaCorrigir > 200 || arquivosParaPodar > 200;

  if (!madrugada && !muitosArquivos) return;

  // Primeira linha com frase-chave esperada pelos testes
  logConselheiro.respira();
  if (madrugada) {
    // Mensagem deve conter a expressão "passa das 2h" para testes
    const horaRef = hora >= 2 && hora < 3 ? '2h' : `${hora}h`;
    logConselheiro.madrugada(horaRef);
  }
  if (muitosArquivos) {
    // Deve conter "volume de tarefas" (minúsculas) para os testes
    logConselheiro.volumeAlto();
  }
  logConselheiro.cuidado();
}

// SPDX-License-Identifier: MIT
// @prometheus-disable tipo-literal-inline-complexo
// Justificativa: tipos locais para filtragem de relatórios
// Sistema inteligente de filtragem e priorização de relatórios
// Agrupa problemas similares e prioriza por impacto para evitar sobrecarga de informação

import { getMessages } from '@core/messages';
import type { Ocorrencia, OcorrenciaNivel, ProblemaAgrupado, RelatorioResumo } from '@prometheus';

const { AGRUPAMENTOS_MENSAGEM, PRIORIDADES, RelatorioMensagens } = getMessages();

/**
 * Processa e filtra ocorrências para gerar um relatório resumido inteligente
 */

export function processarRelatorioResumo(ocorrencias: Ocorrencia[], limitePrioridade = 30): RelatorioResumo {
  // Agrupar ocorrências por tipo e padrões de mensagem
  const gruposPorTipo = new Map<string, Ocorrencia[]>();
  const gruposPorMensagem = new Map<string, Ocorrencia[]>();

  // Agrupar por tipo primeiro
  for (const ocorrencia of ocorrencias) {
    const tipo = String(ocorrencia.tipo || 'OUTROS');
    if (!gruposPorTipo.has(tipo)) {
      gruposPorTipo.set(tipo, []);
    }
    const grupo = gruposPorTipo.get(tipo);
    if (grupo) {
      grupo.push(ocorrencia);
    }
  }

  // Agrupar por padrões de mensagem
  for (const ocorrencia of ocorrencias) {
    const mensagem = String(ocorrencia.mensagem || '');
    let agrupado = false;
    for (const grupo of AGRUPAMENTOS_MENSAGEM) {
      if (grupo.padrao.test(mensagem)) {
        if (!gruposPorMensagem.has(grupo.categoria)) {
          gruposPorMensagem.set(grupo.categoria, []);
        }
        const categoriaGrupo = gruposPorMensagem.get(grupo.categoria);
        if (categoriaGrupo) {
          categoriaGrupo.push(ocorrencia);
        }
        agrupado = true;
        break;
      }
    }
    if (!agrupado) {
      const tipo = String(ocorrencia.tipo || 'OUTROS');
      if (!gruposPorMensagem.has(tipo)) {
        gruposPorMensagem.set(tipo, []);
      }
      const tipoGrupo = gruposPorMensagem.get(tipo);
      if (tipoGrupo) {
        tipoGrupo.push(ocorrencia);
      }
    }
  }

  // Converter grupos em problemas agrupados
  const problemasAgrupados: ProblemaAgrupado[] = [];

  // Processar grupos por tipo
  for (const [tipo, ocorrenciasTipo] of gruposPorTipo) {
    const config = PRIORIDADES[tipo] || {
      prioridade: 'baixa' as const,
      icone: '??'
    };

    // Verificar se já existe agrupamento por mensagem
    const jaAgrupado = Array.from(gruposPorMensagem.keys()).some(categoria => {
      const ocorrenciasGrupo = gruposPorMensagem.get(categoria) || [];
      return ocorrenciasGrupo.some(o => o.tipo === tipo);
    });
    if (!jaAgrupado && ocorrenciasTipo.length > 0) {
      problemasAgrupados.push({
        categoria: tipo,
        prioridade: config.prioridade,
        icone: config.icone,
        titulo: formatarTituloTipo(tipo),
        quantidade: ocorrenciasTipo.length,
        ocorrencias: ocorrenciasTipo,
        resumo: gerarResumoOcorrencias(ocorrenciasTipo)
      });
    }
  }

  // Processar grupos por mensagem (prioritários)
  for (const agrupamento of AGRUPAMENTOS_MENSAGEM) {
    const ocorrenciasGrupo = gruposPorMensagem.get(agrupamento.categoria) || [];
    if (ocorrenciasGrupo.length > 0) {
      problemasAgrupados.push({
        categoria: agrupamento.categoria,
        prioridade: 'critica',
        // Grupos de mensagem são sempre prioritários
        icone: '??',
        titulo: agrupamento.titulo,
        quantidade: ocorrenciasGrupo.length,
        ocorrencias: ocorrenciasGrupo,
        resumo: `${ocorrenciasGrupo.length} ocorrências detectadas`,
        acaoSugerida: agrupamento.acaoSugerida
      });
    }
  }

  // Ordenar por prioridade e quantidade
  problemasAgrupados.sort((a, b) => {
    const prioridadeOrdem = {
      critica: 0,
      alta: 1,
      media: 2,
      baixa: 3
    };
    const prioA = prioridadeOrdem[a.prioridade];
    const prioB = prioridadeOrdem[b.prioridade];
    if (prioA !== prioB) return prioA - prioB;
    return b.quantidade - a.quantidade; // Mais ocorrências primeiro
  });

  // Separar por n�veis de prioridade
  const problemasCriticos = problemasAgrupados.filter(p => p.prioridade === 'critica');
  const problemasAltos = problemasAgrupados.filter(p => p.prioridade === 'alta');
  const problemasOutros = problemasAgrupados.filter(p => ['media', 'baixa'].includes(p.prioridade));

  // Calcular estat�sticas
  const arquivosAfetados = new Set(ocorrencias.map(o => o.relPath).filter(path => path && path !== 'undefined')).size;
  const problemasPrioritarios = problemasCriticos.length + problemasAltos.length;
  return {
    problemasCriticos: problemasCriticos.slice(0, limitePrioridade / 3),
    problemasAltos: problemasAltos.slice(0, limitePrioridade / 3),
    problemasOutros: problemasOutros.slice(0, limitePrioridade / 3),
    estatisticas: {
      totalOcorrencias: ocorrencias.length,
      arquivosAfetados,
      problemasPrioritarios,
      problemasAgrupados: problemasAgrupados.length
    }
  };
}

/**
 * Formata o título do tipo de problema para exibição
 */

function formatarTituloTipo(tipo: string): string {
  const titulos: Record<string, string> = {
    PROBLEMA_SEGURANCA: 'Problemas de Segurança',
    VULNERABILIDADE_SEGURANCA: 'Vulnerabilidades de Segurança',
    CODIGO_FRAGIL: 'Código Frágil',
    PROBLEMA_TESTE: 'Problemas de Teste',
    PROBLEMA_DOCUMENTACAO: 'Problemas de Documentação',
    CONSTRUCOES_SINTATICAS: 'Construções Sintáticas',
    ANALISE_ARQUITETURA: 'Análise de Arquitetura',
    CARACTERISTICAS_ARQUITETURA: 'Características de Arquitetura',
    METRICAS_ARQUITETURA: 'Métricas de Arquitetura',
    TODO_PENDENTE: 'TODOs Pendentes',
    'padrao-ausente': 'Padrões Ausentes',
    'estrutura-suspeita': 'Estrutura Suspeita',
    'estrutura-config': 'Configuração de Estrutura',
    'estrutura-entrypoints': 'Pontos de Entrada',
    IDENTIFICACAO_PROJETO: 'Identificação do Projeto',
    SUGESTAO_MELHORIA: 'Sugestões de Melhoria',
    EVIDENCIA_CONTEXTO: 'Evidências de Contexto',
    TECNOLOGIAS_ALTERNATIVAS: 'Tecnologias Alternativas'
  };
  return titulos[tipo] || tipo.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
}

/**
 * Gera um resumo das ocorrências para exibição
 */

function gerarResumoOcorrencias(ocorrencias: Ocorrencia[]): string {
  if (ocorrencias.length === 0) return 'Nenhuma ocorrência';
  const arquivos = new Set(ocorrencias.map(o => o.relPath).filter(Boolean));
  const niveisFrequentes = ocorrencias.map(o => o.nivel).filter((nivel): nivel is OcorrenciaNivel => Boolean(nivel)).reduce((acc, nivel) => {
    acc[nivel] = (acc[nivel] || 0) + 1;
    return acc;
  }, {} as Record<OcorrenciaNivel, number>);
  const nivelMaisFrequente = Object.entries(niveisFrequentes).sort(([, a], [, b]) => (b as number) - (a as number))[0]?.[0];
  let resumo = `${ocorrencias.length} ocorrências`;
  if (arquivos.size > 1) {
    resumo += ` em ${arquivos.size} arquivos`;
  }
  if (nivelMaisFrequente) {
    resumo += ` (maioria: ${nivelMaisFrequente})`;
  }
  return resumo;
}

/**
 * Gera relatório Markdown resumido
 */

export async function gerarRelatorioMarkdownResumo(relatorioResumo: RelatorioResumo, outputCaminho: string): Promise<void> {
  const {
    problemasCriticos,
    problemasAltos,
    problemasOutros,
    estatisticas
  } = relatorioResumo;
  const linhas: string[] = [];

  // Cabeçalho usando mensagens centralizadas
  linhas.push(`# ${RelatorioMensagens.resumo.titulo}`);
  linhas.push('');
  linhas.push(`> ${RelatorioMensagens.resumo.introducao}`);
  linhas.push('');

  // Estatisticas usando mensagens centralizadas
  linhas.push(`## ${RelatorioMensagens.resumo.secoes.estatisticas.titulo}`);
  linhas.push('');
  linhas.push(`- **${RelatorioMensagens.resumo.secoes.estatisticas.totalOcorrencias}**: ${estatisticas.totalOcorrencias.toLocaleString()}`);
  linhas.push(`- **${RelatorioMensagens.resumo.secoes.estatisticas.arquivosAfetados}**: ${estatisticas.arquivosAfetados.toLocaleString()}`);
  linhas.push(`- **${RelatorioMensagens.resumo.secoes.estatisticas.problemasPrioritarios}**: ${estatisticas.problemasPrioritarios}`);
  linhas.push(`- **${RelatorioMensagens.resumo.secoes.estatisticas.problemasAgrupados}**: ${estatisticas.problemasAgrupados}`);
  linhas.push('');

  // Problemas críticos usando mensagens centralizadas
  if (problemasCriticos.length > 0) {
    linhas.push(`## ${RelatorioMensagens.resumo.secoes.criticos.titulo}`);
    linhas.push('');
    for (const problema of problemasCriticos) {
      linhas.push(`### ${problema.icone} ${problema.titulo}`);
      linhas.push('');
      linhas.push(`**${RelatorioMensagens.resumo.labels.quantidade}**: ${problema.quantidade} ocorrências`);
      linhas.push(`**Resumo**: ${problema.resumo}`);
      if (problema.acaoSugerida) {
        linhas.push(`**${RelatorioMensagens.resumo.labels.acaoSugerida}**: ${problema.acaoSugerida}`);
      }
      linhas.push('');

      // Mostrar algumas ocorrências de exemplo
      const exemplos = problema.ocorrencias.slice(0, 3);
      if (exemplos.length > 0) {
        linhas.push(`**${RelatorioMensagens.resumo.labels.exemplos}:**`);
        for (const exemplo of exemplos) {
          const arquivo = exemplo.relPath || 'arquivo desconhecido';
          const linha = exemplo.linha ? `:${exemplo.linha}` : '';
          linhas.push(`- \`${arquivo}${linha}\`: ${exemplo.mensagem}`);
        }
        if (problema.quantidade > 3) {
          linhas.push(`- ... e mais ${problema.quantidade - 3} ocorrências`);
        }
        linhas.push('');
      }
    }
  }

  // Problemas altos usando mensagens centralizadas
  if (problemasAltos.length > 0) {
    linhas.push(`## ${RelatorioMensagens.resumo.secoes.altos.titulo}`);
    linhas.push('');
    for (const problema of problemasAltos) {
      linhas.push(`### ${problema.icone} ${problema.titulo}`);
      linhas.push('');
      linhas.push(`**${RelatorioMensagens.resumo.labels.quantidade}**: ${problema.quantidade} | **Resumo**: ${problema.resumo}`);
      if (problema.acaoSugerida) {
        linhas.push(`**${RelatorioMensagens.resumo.labels.acaoSugerida}**: ${problema.acaoSugerida}`);
      }
      linhas.push('');
    }
  }

  // Outros problemas (resumo) usando mensagens centralizadas
  if (problemasOutros.length > 0) {
    linhas.push(`## ${RelatorioMensagens.resumo.secoes.outros.titulo}`);
    linhas.push('');
    linhas.push('| Categoria | Quantidade | Resumo |');
    linhas.push('|-----------|------------|--------|');
    for (const problema of problemasOutros) {
      linhas.push(`| ${problema.icone} ${problema.titulo} | ${problema.quantidade} | ${problema.resumo} |`);
    }
    linhas.push('');
  }

  // Rodapé
  linhas.push('---');
  linhas.push('');
  linhas.push('?? **Dica**: Para ver todos os detalhes, gere o relatório completo em modo normal.');
  linhas.push('');
  linhas.push(`**Relatório gerado em**: ${new Date().toLocaleString('pt-BR')}`);
  const {
    salvarEstado
  } = await import('@shared/persistence');
  await salvarEstado(outputCaminho, linhas.join('\n'));
}

/**
 * Gera resumo executivo mostrando apenas problemas críticos e de alta prioridade
 * Ideal para tomada de decisão e overview rápido
 */

export function gerarResumoExecutivo(ocorrencias: Ocorrencia[]): {
  problemasCriticos: number;
  problemasAltos: number;
  vulnerabilidades: number;
  quickFixes: number;
  recomendacao: 'verde' | 'amarelo' | 'vermelho';
  mensagem: string;
  detalhes: ProblemaAgrupado[];
} {
  const relatorio = processarRelatorioResumo(ocorrencias);
  const problemasCriticos = relatorio.problemasCriticos.reduce((sum: number, p: ProblemaAgrupado) => sum + p.quantidade, 0);
  const problemasAltos = relatorio.problemasAltos.reduce((sum: number, p: ProblemaAgrupado) => sum + p.quantidade, 0);

  // Contadores específicos
  const vulnerabilidades = ocorrencias.filter(o => o.tipo === 'VULNERABILIDADE_SEGURANCA' || o.tipo === 'PROBLEMA_SEGURANCA').length;
  const quickFixes = ocorrencias.filter(o => o.tipo === 'QUICK_FIX_DISPONIVEL').length;

  // Determina recomendação baseada em prioridade
  let recomendacao: 'verde' | 'amarelo' | 'vermelho';
  let mensagem: string;
  if (problemasCriticos > 10) {
    recomendacao = 'vermelho';
    mensagem = `?? CRÍTICO: ${problemasCriticos} problemas de segurança/estabilidade. Ação imediata necessária.`;
  } else if (problemasCriticos > 0 || problemasAltos > 50) {
    recomendacao = 'amarelo';
    mensagem = `?? ATENÇÃO: ${problemasCriticos} críticos, ${problemasAltos} altos. Planeje correções.`;
  } else {
    recomendacao = 'verde';
    mensagem = `? BOM: Apenas problemas menores. ${quickFixes} correções automáticas disponíveis.`;
  }
  return {
    problemasCriticos,
    problemasAltos,
    vulnerabilidades,
    quickFixes,
    recomendacao,
    mensagem,
    detalhes: [...relatorio.problemasCriticos, ...relatorio.problemasAltos]
  };
}

// SPDX-License-Identifier: MIT
// Gerador de relatórios: Markdown e JSON
import { getMessages } from '@core/messages';
import type { GeradorMarkdownOptions, Ocorrencia, ResultadoInquisicaoCompleto } from '@prometheus';

export async function gerarRelatorioMarkdown(resultado: ResultadoInquisicaoCompleto, outputCaminho: string, modoBrief = false, options?: GeradorMarkdownOptions): Promise<void> {
  const { gerarHeaderRelatorio, gerarSecaoGuardian, gerarTabelaOcorrencias, gerarTabelaResumoTipos, RelatorioMensagens } = getMessages();

  const {
    totalArquivos = 0,
    ocorrencias = [],
    guardian,
    timestamp = Date.now(),
    duracaoMs = 0,
    metricas
  } = (resultado || {}) as ResultadoInquisicaoCompleto;
  const dataISO = new Date(timestamp).toISOString();

  // Se modo brief, usar filtro inteligente
  if (modoBrief) {
    const {
      processarRelatorioResumo,
      gerarRelatorioMarkdownResumo
    } = await import('./filtro-inteligente.js');
    const relatorioResumo = processarRelatorioResumo(ocorrencias);
    await gerarRelatorioMarkdownResumo(relatorioResumo, outputCaminho);
    return;
  }
  const ocorrenciasOrdenadas: Ocorrencia[] = [...ocorrencias].sort((a, b) => {
    const ra = String(a.relPath ?? '');
    const rb = String(b.relPath ?? '');
    const cmp = ra.localeCompare(rb);
    if (cmp !== 0) return cmp;
    const la = typeof a.linha === 'number' ? a.linha : Number.MAX_SAFE_INTEGER;
    const lb = typeof b.linha === 'number' ? b.linha : Number.MAX_SAFE_INTEGER;
    return la - lb;
  });

  // Extrair dados do Guardian
  const guardianData = guardian && typeof guardian === 'object' ? {
    status: 'status' in guardian ? String((guardian as Record<string, unknown>).status) : 'não executada',
    timestamp: 'timestamp' in guardian ? String((guardian as Record<string, unknown>).timestamp) : '—',
    totalArquivos: 'totalArquivos' in guardian ? String((guardian as Record<string, unknown>).totalArquivos) : '—'
  } : {
    status: 'não executada',
    timestamp: '—',
    totalArquivos: '—'
  };

  // Montar o header usando template centralizado
  const lines: string[] = [];
  lines.push(...gerarHeaderRelatorio({
    dataISO,
    duracao: duracaoMs,
    totalArquivos,
    totalOcorrencias: ocorrencias.length
  }));

  // Adicionar métricas importantes no início para desenvolvedor
  if (metricas) {
    lines.push('## Métricas do Projeto');
    lines.push('');
    lines.push('| Métrica | Valor |');
    lines.push('|--------|-------|');
    if (metricas.totalArquivos !== undefined) {
      lines.push(`| Total de Arquivos | ${metricas.totalArquivos} |`);
    }
    if (metricas.tempoParsingMs !== undefined) {
      lines.push(`| Tempo de Parsing | ${(metricas.tempoParsingMs / 1000).toFixed(2)}s |`);
    }
    if (metricas.tempoAnaliseMs !== undefined) {
      lines.push(`| Tempo de Análise | ${(metricas.tempoAnaliseMs / 1000).toFixed(2)}s |`);
    }
    if (metricas.cacheAstHits !== undefined && metricas.cacheAstMiss !== undefined) {
      const hitRate = metricas.cacheAstMiss > 0 ? (metricas.cacheAstHits / (metricas.cacheAstHits + metricas.cacheAstMiss) * 100).toFixed(1) : '100';
      lines.push(`| Cache AST | ${hitRate}% (${metricas.cacheAstHits} hits / ${metricas.cacheAstMiss} miss) |`);
    }
    // Top analistas por duração
    if (metricas.analistas && metricas.analistas.length > 0) {
      lines.push('');
      lines.push('### Analistas mais lentos');
      lines.push('');
      lines.push('| Analista | Duração | Ocorrências |');
      lines.push('|----------|---------|------------|');
      const topAnalistas = [...metricas.analistas].sort((a, b) => (b.duracaoMs || 0) - (a.duracaoMs || 0)).slice(0, 5);
      for (const a of topAnalistas) {
        lines.push(`| ${a.nome} | ${(a.duracaoMs || 0).toFixed(0)}ms | ${a.ocorrencias || 0} |`);
      }
    }
    lines.push('');
    lines.push('---\n');
  }

  // Se houver manifest, adiciona link e sumário rápido
  if (options && options.manifestFile && options.relatoriosDir) {
    const relPath = options.manifestFile;
    lines.push(`**${RelatorioMensagens.principal.secoes.metadados.arquivoManifest}:** \`${relPath}\`  `);
    lines.push('');
    lines.push(`> ${RelatorioMensagens.principal.secoes.metadados.notaManifest}`);
    lines.push('');
    lines.push('---');
    lines.push('');
  }

  // Seção Guardian usando template
  lines.push(...gerarSecaoGuardian(guardianData));

  // Sumário das ocorrências por tipo usando template
  const tiposContagem: Record<string, number> = {};
  for (const ocorrencia of ocorrencias) {
    const tipo = ocorrencia && (ocorrencia as Ocorrencia).tipo || 'desconhecido';
    tiposContagem[String(tipo)] = (tiposContagem[String(tipo)] || 0) + 1;
  }
  lines.push(...gerarTabelaResumoTipos(tiposContagem, 10));

  // Tabela com ocorrências usando template
  lines.push('---');
  lines.push('');
  lines.push(`## ${RelatorioMensagens.principal.secoes.ocorrencias.titulo} (amostra)`);
  lines.push('');
  const AMOSTRA_MAX = 2000;
  const sample = ocorrenciasOrdenadas.slice(0, AMOSTRA_MAX);
  lines.push(...gerarTabelaOcorrencias(sample));
  if (ocorrenciasOrdenadas.length > AMOSTRA_MAX) {
    lines.push('');
    lines.push(`> Mostrando apenas ${AMOSTRA_MAX} ocorrências. Para ver todas, consulte os shards listados no manifest.`);
  }
  const {
    salvarEstado
  } = await import('@shared/persistence');
  await salvarEstado(outputCaminho, lines.join('\n'));
}
export async function gerarRelatorioJson(resultado: ResultadoInquisicaoCompleto, outputCaminho: string): Promise<void> {
  // Importar sistema de versionamento
  const {
    criarRelatorioComVersao
  } = await import('@core/schema');

  // Criar relatório versionado (mantemos metadados, mas salvamos os dados brutos para compatibilidade)
  const relatorioVersionado = criarRelatorioComVersao(resultado, undefined, 'Relatório completo de diagnóstico do Prometheus');
  const {
    salvarEstado
  } = await import('@shared/persistence');
  await salvarEstado(outputCaminho, relatorioVersionado.dados ?? resultado);
}

