// SPDX-License-Identifier: MIT
/**
 * Utilidades de JSON: escape Unicode e stringificação segura para consumidores legados.
 *
 * Regras:
 * - Converte qualquer caractere fora do ASCII básico em sequências \uXXXX.
 * - Para caracteres fora do BMP, emite pares substitutos (dois \uXXXX).
 * - Mantém caracteres ASCII intactos.
 */

// Constantes Unicode e BMP
const ASCII_MAX = 0x7f;
const BMP_MAX = 0xffff;
const SUPPLEMENTARY_PLANO_DESLOCAMENTO = 0x10000;
const HIGH_SURROGATE_BASE = 0xd800;
const LOW_SURROGATE_BASE = 0xdc00;
const SURROGATE_DESLOCAMENTO = 10;
const SURROGATE_MASCARA = 0x3ff;
const HEX_PAD_LENGTH = 4;
const JSON_INDENTACAO_PADRAO = 2;

/**
 * Escapa caracteres não-ASCII para sequências \uXXXX, incluindo pares substitutos.
 */

export function escapeNonAscii(s: string): string {
  let out = '';
  for (const ch of s) {
    const cp = ch.codePointAt(0);
    if (cp === undefined || cp === null || cp <= ASCII_MAX) {
      out += ch;
    } else if (cp <= BMP_MAX) {
      out += `\\u${cp.toString(16).padStart(HEX_PAD_LENGTH, '0')}`;
    } else {
      // caracteres fora do BMP -> pares substitutos
      const codePointOffset = cp - SUPPLEMENTARY_PLANO_DESLOCAMENTO;
      const highSurrogate = HIGH_SURROGATE_BASE + (codePointOffset >> SURROGATE_DESLOCAMENTO);
      const lowSurrogate = LOW_SURROGATE_BASE + (codePointOffset & SURROGATE_MASCARA);
      out += `\\u${highSurrogate.toString(16).padStart(HEX_PAD_LENGTH, '0')}`;
      out += `\\u${lowSurrogate.toString(16).padStart(HEX_PAD_LENGTH, '0')}`;
    }
  }
  return out;
}

/**
 * Stringifica um objeto em JSON aplicando escapeNonAscii em todos os strings do objeto.
 * Normaliza possíveis double-escapes ("\\uXXXX" -> "\uXXXX").
 */

export function stringifyJsonEscaped(value: unknown, space: number = JSON_INDENTACAO_PADRAO): string {
  const replacer = (_key: string, v: unknown) => typeof v === 'string' ? escapeNonAscii(v) : v;
  const raw = JSON.stringify(value, replacer, space);
  // JSON.stringify pode escapar as barras invertidas inseridas pelo replacer
  // (\\u -> \u). Normalizamos para os consumidores que esperam \uXXXX.
  return raw.replace(/\\\\u/g, '\\u');
}

// SPDX-License-Identifier: MIT
/**
 * Utilitários para trabalhar com relatórios JSON versionados
 */

import { migrarParaVersaoAtual, validarSchema } from '@core/schema';
import type { LeitorRelatorioOptions } from '@prometheus';

import { lerEstado } from '../persistence/persistencia.js';

// Re-exporta o tipo para compatibilidade
export type { LeitorRelatorioOptions };

type RelatorioGenerico = Record<string, unknown>;
type RelatorioVersionado<T = unknown> = RelatorioGenerico & {
  _schema?: Record<string, unknown>;
  dados?: T;
};

/**
 * Lê um relatório JSON versionado do disco
 */
export async function lerRelatorioVersionado<T = unknown>(
  options: LeitorRelatorioOptions,
): Promise<{
  sucesso: boolean;
  dados?: T;
  schema?: Record<string, unknown>;
  erro?: string;
  migrado?: boolean;
}> {
  const { caminho, validar = true, migrar = false } = options;

  try {
    // Ler arquivo
    const conteudo = await lerEstado<Record<string, unknown>>(caminho);

    if (!conteudo) {
      return {
        sucesso: false,
        erro: 'Arquivo não encontrado ou vazio',
      };
    }

    let relatorioFinal = conteudo;
    let migrado = false;

    // Validar schema se solicitado
    if (validar) {
      const validacao = validarSchema(conteudo);
      if (!validacao.valido) {
        return {
          sucesso: false,
          erro: `Schema inválido: ${validacao.erros.join(', ')}`,
        };
      }
    }

    // Migrar se necessário e solicitado.
    // - Se migrar=true: migramos explicitamente.
    // - Se migrar=false e validar=false: aceitamos o conteúdo legado como está (modo permissivo).
    // - Se migrar=false e validar=true: rejeitamos (chamador pediu validação estrita).
    if (!conteudo._schema || !conteudo.dados) {
      if (migrar) {
        relatorioFinal = migrarParaVersaoAtual<unknown>(
          conteudo,
        ) as unknown as Record<string, unknown>;
        migrado = true;
      } else if (!validar) {
        // modo permissivo: aceitar o conteúdo legado sem migrar
        relatorioFinal = conteudo;
        migrado = false;
      } else {
        return {
          sucesso: false,
          erro: 'Relatório em formato antigo (sem _schema); habilite migrar para atualizá-lo explicitamente.',
        };
      }
    }

    // Extrair dados: se for relatório versionado, retornamos apenas `dados`.
    // Se for formato legado (sem _schema), retornamos o objeto inteiro.
    let dados: T;
    const relObj = relatorioFinal as RelatorioVersionado<T>;

    if ('_schema' in relObj && relObj._schema) {
      dados = relObj.dados as T;
    } else {
      dados = relatorioFinal as T;
    }

    return {
      sucesso: true,
      dados,
      schema: (relObj._schema as Record<string, unknown>) || undefined,
      migrado,
    };
  } catch (error) {
    return {
      sucesso: false,
      erro: `Erro ao ler relatório: ${error instanceof Error ? error.message : String(error)}`,
    };
  }
}

/**
 * Lê apenas os dados de um relatório, ignorando metadados de versão
 */
export async function lerDadosRelatorio<T = unknown>(
  caminho: string,
): Promise<{
  sucesso: boolean;
  dados?: T;
  erro?: string;
}> {
  // Para obtenção superficial de dados, permitimos migração automática aqui
  const resultado = await lerRelatorioVersionado<T>({
    caminho,
    validar: false,
    migrar: true,
  });

  return {
    sucesso: resultado.sucesso,
    dados: resultado.dados,
    erro: resultado.erro,
  };
}

/**
 * Verifica se um relatório tem schema válido
 */

export async function verificarSchemaRelatorio(caminho: string): Promise<{
  valido: boolean;
  versao?: string;
  erros?: string[];
  erro?: string;
}> {
  try {
    const conteudo = await lerEstado<Record<string, unknown>>(caminho);

    if (!conteudo) {
      return {
        valido: false,
        erros: ['Arquivo não encontrado ou vazio'],
      };
    }

    const validacao = validarSchema(conteudo);

    return {
      valido: validacao.valido,
      versao: (conteudo._schema as Record<string, unknown>)?.versao as
        | string
        | undefined,
      erros: validacao.erros,
    };
  } catch (error) {
    return {
      valido: false,
      erro: `Erro ao verificar schema: ${error instanceof Error ? error.message : String(error)}`,
    };
  }
}

