// SPDX-License-Identifier: MIT
/**
 * Sistema de configuração granular de regras
 * Suporta:
 * - Regras por arquivo/diretório (glob patterns)
 * - Overrides específicos
 * - Severidade customizada
 * - Exclusões por padrão de arquivo
 */

import { config } from '@core/config';
import type { RuleConfig, RuleOverride } from '@prometheus';
import { minimatch } from 'minimatch';

export type { RuleConfig, RuleOverride };

/**
 * Verifica se uma regra deve ser aplicada para um arquivo específico
 */
export function isRuleSuppressed(ruleName: string, fileCaminho: string): boolean {
  // Normaliza o caminho do arquivo (remove ./ e normaliza barras)
  const normalizedCaminho = fileCaminho.replace(/^\.\//, '').replace(/\\/g, '/');

  // 1. Verifica suppressRules globais (config antigo - compatibilidade)
  const configData = config as unknown as {
    suppressRules?: string[];
    rules?: Record<string, RuleConfig>;
    testPadroes?: {
      files?: string[];
      allowAnyType?: boolean;
    };
  };
  const suppressRules = configData.suppressRules;
  if (suppressRules?.includes(ruleName)) {
    return true;
  }

  // 2. Verifica config.rules (novo sistema)
  const ruleConfiguracao = configData.rules?.[ruleName];
  if (ruleConfiguracao) {
    // Verifica se severity é 'off'
    if (ruleConfiguracao.severity === 'off') {
      return true;
    }

    // Verifica se arquivo está em exclude patterns
    if (ruleConfiguracao.exclude) {
      for (const pattern of ruleConfiguracao.exclude) {
        if (minimatch(normalizedCaminho, pattern, {
          dot: true
        })) {
          return true;
        }
      }
    }

    // Verifica allowTestFiles para arquivos de teste
    if (ruleConfiguracao.allowTestFiles && isTestArquivo(normalizedCaminho, configData)) {
      return true;
    }
  }

  // 3. Verifica padrões de teste globais (para tipo-inseguro em testes)
  if (ruleName === 'tipo-inseguro' || ruleName === 'tipo-inseguro-any') {
    const testPadroes = configData.testPadroes;
    if (testPadroes?.allowAnyType && isTestArquivo(normalizedCaminho, configData)) {
      return true;
    }
  }
  return false;
} /**
 * Verifica se um arquivo é de teste baseado nos padrões configurados
 */
export function isTestArquivo(
  fileCaminho: string,
  configData?: {
    testPadroes?: {
      files?: string[];
    };
  }
): boolean {
  const data = configData || (config as unknown as {
    testPadroes?: {
      files?: string[];
    };
  });
  const testPadroes =
    data.testPadroes?.files || [
      '**/*.test.*',
      '**/*.spec.*',
      'test/**/*',
      'tests/**/*',
      '**/__tests__/**',
    ];
  const normalizedCaminho = fileCaminho.replace(/\\/g, '/');
  return testPadroes.some((pattern: string) =>
    minimatch(normalizedCaminho, pattern, {
      dot: true,
    }),
  );
}

/**
 * Obtém a severidade configurada para uma regra
 */
export function getRuleSeverity(ruleName: string, fileCaminho: string): 'error' | 'warning' | 'info' | undefined {
  const configData = config as unknown as {
    rules?: Record<string, RuleConfig>;
  };
  const ruleConfiguracao = configData.rules?.[ruleName];
  if (!ruleConfiguracao) {
    return undefined;
  }

  // Se regra está suprimida, retorna undefined
  if (isRuleSuppressed(ruleName, fileCaminho)) {
    return undefined;
  }

  // Mapeia severidades
  if (ruleConfiguracao.severity === 'error') return 'error';
  if (ruleConfiguracao.severity === 'warning') return 'warning';
  if (ruleConfiguracao.severity === 'info') return 'info';
  return undefined;
}

/**
 * Verifica se uma ocorrência deve ser suprimida baseado na configuração
 */
export function shouldSuppressOccurrence(tipo: string, fileCaminho: string, _severity?: string): boolean {
  // Extrai o nome base da regra
  // tipo-inseguro-any -> tipo-inseguro
  // tipo-inseguro-any-assertion -> tipo-inseguro
  // tipo-inseguro-any-cast -> tipo-inseguro
  // tipo-inseguro-unknown -> tipo-inseguro
  const baseRuleNome = tipo.replace(/-(any|unknown|assertion|cast).*$/, '');

  // Verifica supressão para regra base e variantes
  const rulesToCheck = [tipo, baseRuleNome];
  return rulesToCheck.some(rule => isRuleSuppressed(rule, fileCaminho));
}

// SPDX-License-Identifier: MIT
/**
 * Sistema de supressão inline para o Prometheus
 * Permite desabilitar regras específicas usando comentários no código
 *
 * Formatos suportados (qualquer sintaxe de comentário inline, ex.: //, #, --, ;, <!-- -->, blocos /* ... * /):
 * - @prometheus-disable-next-line nome-da-regra
 * - @prometheus-disable nome-da-regra
 * - @prometheus-enable nome-da-regra
 */

import type { RegrasSuprimidas, SupressaoInfo } from '@prometheus';

export type { RegrasSuprimidas, SupressaoInfo };

/**
 * Analisa comentários do código fonte para extrair diretivas de supressão
 */
export function extrairSupressoes(src: string): RegrasSuprimidas {
  const linhas = src.split('\n');
  const porLinha = new Map<number, Set<string>>();
  const blocosAtivos = new Set<string>();

  const normalizarLinha = (linha: string): string => {
    let t = linha.trim();

    // Remove wrappers de comentários comuns (ordem importa para HTML -> bloco -> linha)
    if (t.startsWith('<!--'))
      t = t
        .replace(/^<!--/, '')
        .replace(/--!?>(\s*)?$/, '')
        .trim();
    if (t.startsWith('/*'))
      t = t.replace(/^\/\*/, '').replace(/\*\/$/, '').trim();
    if (t.startsWith('*')) t = t.replace(/^\*\s?/, '').trim(); // linhas internas de bloco

    // Comentários de linha: JS/TS, shell/Python, SQL, INI, outros
    t = t.replace(/^\/\//, '').trim();
    t = t.replace(/^#/, '').trim();
    t = t.replace(/^--/, '').trim();
    t = t.replace(/^;/, '').trim();

    return t;
  };

  for (let i = 0; i < linhas.length; i++) {
    const linha = linhas[i];
    const linhaNorm = normalizarLinha(linha);
    const numeroLinha = i + 1;

    // @prometheus-disable-next-line regra1 regra2
    const matchNextLine = linhaNorm.match(/@prometheus-disable-next-line\s+(.+)/);
    if (matchNextLine) {
      const regras = matchNextLine[1].trim().split(/\s+/);
      const linhaAfetada = numeroLinha + 1;

      if (!porLinha.has(linhaAfetada)) {
        porLinha.set(linhaAfetada, new Set());
      }

      regras.forEach((regra) => {
        porLinha.get(linhaAfetada)?.add(regra.trim());
      });

      continue;
    }

    // @prometheus-disable regra1 regra2
    const matchDisable = linhaNorm.match(/@prometheus-disable\s+(.+)/);
    if (matchDisable) {
      const regras = matchDisable[1].trim().split(/\s+/);
      regras.forEach((regra) => {
        blocosAtivos.add(regra.trim());
      });
      continue;
    }

    // @prometheus-enable regra1 regra2
    const matchEnable = linhaNorm.match(/@prometheus-enable\s+(.+)/);
    if (matchEnable) {
      const regras = matchEnable[1].trim().split(/\s+/);
      regras.forEach((regra) => {
        blocosAtivos.delete(regra.trim());
      });
      continue;
    }

    // @prometheus-disable (desabilita todas as regras)
    if (linhaNorm.includes('@prometheus-disable-all')) {
      blocosAtivos.add('*');
      continue;
    }

    // @prometheus-enable (reabilita todas as regras)
    if (linhaNorm.includes('@prometheus-enable-all')) {
      blocosAtivos.clear();
      continue;
    }

    // Se há blocos ativos, aplicar a esta linha
    if (blocosAtivos.size > 0) {
      if (!porLinha.has(numeroLinha)) {
        porLinha.set(numeroLinha, new Set());
      }

      blocosAtivos.forEach((regra) => {
        porLinha.get(numeroLinha)?.add(regra);
      });
    }
  }

  return { porLinha, blocosAtivos };
}

/**
 * Verifica se uma regra está suprimida em uma determinada linha
 */
export function isRegraSuprimida(
  regra: string,
  linha: number,
  supressoes: RegrasSuprimidas,
): boolean {
  const regrasDaLinha = supressoes.porLinha.get(linha);

  if (!regrasDaLinha) {
    return false;
  }

  // Verifica supressão específica da regra
  if (regrasDaLinha.has(regra)) {
    return true;
  }

  // Verifica supressão global (*)
  if (regrasDaLinha.has('*')) {
    return true;
  }

  return false;
}

/**
 * Filtra ocorrências baseado em supressões inline
 */
export function filtrarOcorrenciasSuprimidas<
  T extends { linha?: number; tipo?: string },
>(ocorrencias: T[], nomeAnalista: string, src: string): T[] {
  const supressoes = extrairSupressoes(src);

  return ocorrencias.filter((ocorrencia) => {
    if (!ocorrencia.linha) {
      return true; // Mantém ocorrências sem linha (não podem ser suprimidas)
    }

    // Prioriza tipo específico da ocorrência, depois nome do analista
    const _identificadorRegra = ocorrencia.tipo || nomeAnalista || '';

    // Verifica se está suprimida pelo tipo específico OU pelo nome do analista
    const suprimidaPorTipo =
      ocorrencia.tipo &&
      isRegraSuprimida(ocorrencia.tipo, ocorrencia.linha, supressoes);
    const suprimidaPorAnalista = isRegraSuprimida(
      nomeAnalista,
      ocorrencia.linha,
      supressoes,
    );

    return !suprimidaPorTipo && !suprimidaPorAnalista;
  });
}

