export function criarOcorrencia(
  base: Pick<OcorrenciaBase, 'mensagem' | 'relPath'> & Partial<OcorrenciaBase>,
): OcorrenciaBase {
  return {
    nivel: 'info',
    origem: 'prometheus',
    ...base,
    mensagem: base.mensagem.trim(),
  };
}

