export function isBabelNode(obj: unknown): obj is BabelNode {
  // Implementação de runtime fica em src/@types ou em utilitários reais.
  return (
    typeof obj === 'object' &&
    obj !== null &&
    typeof (obj as Record<string, unknown>).type === 'string'
  );
}

